import { createSignal } from "../signal/signal.js";
export const dragX = createSignal(-1);
export const dragY = createSignal(-1);
export const dragData = createSignal(null);
export const dragStyleEl = createSignal(null);
export const dragBlankEl = createSignal(null);
export const dragActiveDrop = createSignal(null);
export const horizontalDirection = createSignal("start");
export const verticalDirection = createSignal("bottom");
export const clearDragGlobals = () => {
    horizontalDirection("start");
    verticalDirection("bottom");
    dragX(-1);
    dragY(-1);
    dragData(null);
    dragStyleEl()?.remove();
    dragStyleEl(null);
    dragBlankEl()?.remove();
    dragBlankEl(null);
    dragActiveDrop(null);
};
